// Fields validation for the form, generated by BRL_frm1.for
// Version-1.0 2023/07/05

function LargeFloat(webpage, windowname, pagewidth, pageheight) {
  launch = window.open (webpage, windowname, 'width='+pagewidth+',height='+pageheight
                       +',toolbar=0,location=0,directories=0,status=0,menubar=0,scrollbars=1,resizable=1');
}

function Wfloat(webpage,windowname,pagewidth,pageheight) {
  launch = window.open (webpage,windowname, 'width='+pagewidth+',height='+pageheight
                       +',toolbar=0,location=0,directories=0,status=0,menubar=0,scrollbars=1,resizable=1');
}

function valid_chars(str) {
// This is full ASCII pattern:
// var pattern = new RegExp(/^[\r\n\s\w!"#$%&'()*+,-./:;<=>?@\\\[\]^{|}~]*$/);
// where \s stands for both spaces and tabs and \w is the same as [a-zA-Z0-9_]
// This is restricted to what we allow in forms (exclude: "$'<>\|)
   var pattern = new RegExp(/^[\r\n\s\w!#%&()*+,-./:;=?@\[\]^{}~]*$/);
   return pattern.test(str);
}

function valid_code_chars(str) {
// This is restricted to what we allow in the material code:
// \w is a metacharacter matching word characters: [a-zA-Z0-9_]
   var pattern = new RegExp(/^[\s\w()+-.]*$/);
   return pattern.test(str);
}

function brlfrm2_validate() {

  if (document.brlfrm2.thickness.value.length == 0) {
    alert('Please fill the crystal thickness');
    return false;
  }
  else if (isNaN(document.brlfrm2.thickness.value)) {
    alert('The crystal thickness is not numeric');
    return false;
  }
  else if (document.brlfrm2.thickness.value <= 0) {
    alert('Crystal thickness must be a positive number.');
    return false;
  }

  if (document.brlfrm2.ipol.value == 1) {
    if (document.brlfrm2.polang.value.length == 0) {
      alert('Please fill the Angle to pi0');
      return false;
    }
    else if (isNaN(document.brlfrm2.polang.value)) {
      alert('The Angle to pi0 is not numeric');
      return false;
    }
    else if (document.brlfrm2.polang.value < -360 || document.brlfrm2.polang.value > 360) {
      alert('Angle to pi0 must be in range [-360 : +360] degr.');
      return false;
    }
  }

  if (document.brlfrm2.nq1.value.length == 0) {
    alert('Please fill the number of scan points over Theta1');
    return false;
  }
  else if (isNaN(document.brlfrm2.nq1.value)) {
    alert('The number of scan points over Theta1 is not numeric');
    return false;
  }
  else if (document.brlfrm2.nq1.value <= 0 || document.brlfrm2.nq1.value > 501) {
    alert('The number of scan points over Theta1 is not in range: [1-501]');
    return false;
  }

  if (document.brlfrm2.nq2.value.length == 0) {
    alert('Please fill the number of scan points over Theta2');
    return false;
  }
  else if (isNaN(document.brlfrm2.nq2.value)) {
    alert('The number of scan points over Theta2 is not numeric');
    return false;
  }
  else if (document.brlfrm2.nq2.value <= 0 || document.brlfrm2.nq2.value > 501) {
    alert('The number of scan points over Theta2 is not in range: [1-501]');
    return false;
  }

  var factor = 1.;
  var Scan_Max = 5;							//in degr.
  if      (document.brlfrm2.units.value == 0) {factor = 1.;}		//degr.
  else if (document.brlfrm2.units.value == 1) {factor = 60.;}		//min.
  else if (document.brlfrm2.units.value == 2) {factor = 17.4532925;}	//mrad
  else if (document.brlfrm2.units.value == 3) {factor = 3600;}		//sec
  else if (document.brlfrm2.units.value == 4) {factor = 17453.2925;}	//urad

  if (document.brlfrm2.q1min.value.length == 0) {
    alert('Please fill the lower scan limit over Theta1');
    return false;
  }
  else if (isNaN(document.brlfrm2.q1min.value)) {
    alert('The lower scan limit over Theta1 is not numeric');
    return false;
  }
  var q1mi = parseFloat(document.brlfrm2.q1min.value) / factor;
  if (q1mi < -Scan_Max || q1mi >  Scan_Max) {
    alert('The lower scan limit over Theta1 ['+q1mi+']is not in range [-'+Scan_Max+':'+Scan_Max+'] degr.');
    return false;
  }

  if (document.brlfrm2.q1max.value.length == 0) {
    alert('Please fill the upper scan limit over Theta1');
    return false;
  }
  else if (isNaN(document.brlfrm2.q1max.value)) {
    alert('The upper scan limit over Theta1 is not numeric');
    return false;
  }
  var q1ma = parseFloat(document.brlfrm2.q1max.value) / factor;
  if (q1ma < -Scan_Max || q1ma >  Scan_Max) {
    alert('The upper scan limit over Theta1 ['+q1ma+'] is not in range [-'+Scan_Max+':'+Scan_Max+'] degr.');
    return false;
  }

  if (document.brlfrm2.q2min.value.length == 0) {
    alert('Please fill the lower scan limit over Theta2');
    return false;
  }
  else if (isNaN(document.brlfrm2.q2min.value)) {
    alert('The lower scan limit over Theta2 is not numeric');
    return false;
  }
  var q2mi = parseFloat(document.brlfrm2.q2min.value) / factor;
  if (q2mi < -Scan_Max || q2mi >  Scan_Max) {
    alert('The lower scan limit over Theta2 ['+q2mi+'] is not in range [-'+Scan_Max+':'+Scan_Max+'] degr.');
    return false;
  }

  if (document.brlfrm2.q2max.value.length == 0) {
    alert('Please fill the upper scan limit over Theta2');
    return false;
  }
  else if (isNaN(document.brlfrm2.q2max.value)) {
    alert('The upper scan limit over Theta2 is not numeric');
    return false;
  }
  var q2ma = parseFloat(document.brlfrm2.q2max.value) / factor;
  if (q2ma < -Scan_Max || q2ma >  Scan_Max) {
    alert('The upper scan limit over Theta2 ['+q2ma+'] is not in range [-'+Scan_Max+':'+Scan_Max+'] degr.');
    return false;
  }

   return true;
}
